import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { elements } = props;

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const lowerQuery = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerQuery) ||
        el.symbol.toLowerCase().includes(lowerQuery)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    return Array.from(new Set(elements.map((el) => el.category)));
  }, [elements]);

  const getCategoryColor = useCallback((category: string) => {
    const CATEGORY_COLORS: Record<string, string> = {
      'diatomic nonmetal': 'var(--ggui-color-blue-500)',
      'noble gas': 'var(--ggui-color-indigo-500)',
      'alkali metal': 'var(--ggui-color-red-500)',
      'alkaline earth metal': 'var(--ggui-color-orange-500)',
      'metalloid': 'var(--ggui-color-teal-500)',
      'polyatomic nonmetal': 'var(--ggui-color-cyan-500)',
      'post-transition metal': 'var(--ggui-color-green-500)',
      'transition metal': 'var(--ggui-color-yellow-500)',
      'lanthanide': 'var(--ggui-color-purple-500)',
      'actinide': 'var(--ggui-color-pink-500)',
    };
    return CATEGORY_COLORS[category] || 'var(--ggui-color-gray-500)';
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
  };
}


