// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

export function useComponent(props: Props): HookReturn {
  const { initialProfile } = props;
  const totalSteps = 3;

  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<ProfileData>(() => ({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? '',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? false,
    theme: initialProfile?.theme ?? 'light',
  }));

  const updateField = useCallback(<K extends keyof ProfileData>(key: K, value: ProfileData[K]) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  }, []);

  const nextStep = useCallback(() => {
    setCurrentStep((prev) => Math.min(prev + 1, totalSteps - 1));
  }, []);

  const prevStep = useCallback(() => {
    setCurrentStep((prev) => Math.max(prev - 1, 0));
  }, []);

  const isStepValid = useMemo(() => {
    switch (currentStep) {
      case 0:
        return formData.name.trim() !== '' && validateEmail(formData.email);
      case 1:
        return formData.role !== '';
      case 2:
        return true;
      default:
        return false;
    }
  }, [currentStep, formData]);

  return {
    currentStep,
    formData,
    updateField,
    nextStep,
    prevStep,
    isStepValid,
    totalSteps,
  };
}


