import type { ProfileFormProps } from '/virtual/types';
// components/ProfileForm.tsx — reusable sub-component
import React, { useState } from 'react';
import { Container, Card, Stack, Button, Progress } from '@ggui-ai/design/primitives';

export function ProfileForm(props: ProfileFormProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || props.roleOptions[0],
    emailNotifications: props.initialProfile?.emailNotifications || false,
    theme: props.initialProfile?.theme || 'light',
  });

  const updateData = (data: Partial<ProfileData>) => {
    setFormData((prev) => ({ ...prev, ...data }));
  };

  const isValid = currentStep === 1 ? formData.name !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) : true;

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <StepIndicator currentStep={currentStep} totalSteps={3} />
        <Progress value={(currentStep / 3) * 100} variant="default" size="md" />

        <Card padding={24} shadow="md">
          {currentStep === 1 && (
            <ProfileSetupForm data={formData} onChange={updateData} avatarOptions={props.avatarOptions} />
          )}
          {currentStep === 2 && (
            <PreferencesForm data={formData} onChange={updateData} roleOptions={props.roleOptions} />
          )}
          {currentStep === 3 && <ReviewSummary data={formData} />}
        </Card>

        <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 'var(--ggui-spacing-4)' }}>
          <Button 
            variant="ghost" 
            onClick={() => setCurrentStep((s) => s - 1)} 
            disabled={currentStep === 1}
          >
            Back
          </Button>

          {currentStep < 3 ? (
            <Button 
              variant="primary" 
              onClick={() => setCurrentStep((s) => s + 1)} 
              disabled={!isValid}
            >
              Next
